package com.Aga.Agali.config; import com.Aga.Agali.filter.JwtAuthFilter; import com.Aga.Agali.filter.RoleAuthFilter; import org.springframework.cloud.gateway.route.RouteLocator; import org.springframework.cloud.gateway.route.builder.RouteLocatorBuilder; import org.springframework.context.annotation.Bean; import org.springframework.context.annotation.Configuration; @Configuration public class GatewayConfig { private final JwtAuthFilter authFilter; private final RoleAuthFilter roleFilter; public GatewayConfig(JwtAuthFilter authFilter, RoleAuthFilter roleFilter) { this.authFilter = authFilter; this.roleFilter = roleFilter; } @Bean public RouteLocator routeLocator(RouteLocatorBuilder builder) { return builder.routes() .route("user-service-auth", r -> r.path("/api/auth/**").uri("http://user-service:8081")) .route("user-service-user", r -> r.path("/api/user/**").filters(f -> f.filter(authFilter)).uri("http://user-service:8081")) .route("test-service", r -> r.path("/api/test/**").filters(f -> f.filter(authFilter)).uri("http://test-service:8082")) .route("exam-service", r -> r.path("/api/exam/**").filters(f -> f.filter(authFilter)).uri("http://test-service:8082")) .route("statistics-service", r -> r.path("/api/statistics/**").filters(f -> f.filter(authFilter)).uri("http://statistics-service:8083")) .route("learning-plan-service", r -> r.path("/api/learning/**").filters(f -> f.filter(authFilter)).uri("http://learning-service:8084")) .route("notification-service", r -> r.path("/api/notification/**").filters(f -> f.filter(authFilter)).uri("http://notification-service:8085")) .route("permission-service", r -> r.path("/api/permission/**").filters(f -> f.filter(authFilter)).uri("http://permission-service:8086")) .route("payment-service", r -> r.path("/api/payment/**").filters(f -> f.filter(authFilter)).uri("http://payment-service:8087")) .build(); } }
